def test_query_params():
    server = MockServer()
    server.register_route(HttpMethod.GET, '/search', lambda req: HttpResponse(200, req.query_params))
    client = HttpClient(server)
    resp = client.get('/search', query_params={'q': 'test', 'page': '1'})
    assert resp.body == {'q': 'test', 'page': '1'}
